then.script:
var response = mc.getPayloadJSON();
var result;


if (!response || !response.data || !Array.isArray(response.data) || response.data.length === 0) {

    result = {
        policyNumber: null,
        productCode: null,
        endorsements: []
    };

} else {

    var data = response.data;
    var first = data[0];

    result = {
        policyNumber: first.policyNumber ? first.policyNumber : null,
        productCode: first.productCode ? first.productCode : null,

        endorsements: data.map(function (item) {

            // ===== Drivers =====
            var drivers = (item.changes && item.changes.drivers) ? item.changes.drivers : {};
            var driverAdded = drivers.added ? drivers.added : [];
            var driverUpdated = drivers.updated ? drivers.updated : [];
            var driverRemoved = drivers.removed ? drivers.removed : [];

            // ===== Insurable Objects =====
            var objects = (item.changes && item.changes.insurableObjects) ? item.changes.insurableObjects : {};
            var objAdded = objects.added ? objects.added : [];
            var objUpdated = objects.updated ? objects.updated : [];
            var objRemoved = objects.removed ? objects.removed : [];

            // ===== Build insurableObjects =====
            var insurableObjects = objAdded.map(function (obj) {

                var vehicle = obj.vehicle ? obj.vehicle : {};

                var description =
                    (vehicle.vehicleMakeName ? vehicle.vehicleMakeName : "") + " " +
                    (vehicle.vehicleModelName ? vehicle.vehicleModelName : "") + " " +
                    (vehicle.vehicleModelYear ? vehicle.vehicleModelYear.toString() : "");

                description = description.trim();

                return {
                    insurableObjectTypeCode: obj.insurableObjectTypeCode ? obj.insurableObjectTypeCode : null,
                    objectIdentifier: obj.insurableObjectIdentifier ? obj.insurableObjectIdentifier : null,
                    objectDescription: description ? description : null
                };
            });


            var policyCoverages = [];

            for (var i = 0; i < objAdded.length; i++) {

                var coverages = objAdded[i].coverages ? objAdded[i].coverages : [];

                for (var j = 0; j < coverages.length; j++) {

                    var cov = coverages[j];

                    var limit = (cov.limits && cov.limits.length > 0) ? cov.limits[0] : {};
                    var deductible = (cov.deductibles && cov.deductibles.length > 0) ? cov.deductibles[0] : {};

                    policyCoverages.push({
                        coverageName: cov.coverageName ? cov.coverageName : null,
                        limit: {
                            limitAmount: limit.limitAmount ? limit.limitAmount : null,
                            currencyCode: limit.currencyCode ? limit.currencyCode : null
                        },
                        deductible: {
                            deductibleAmount: deductible.deductibleAmount ? deductible.deductibleAmount : null,
                            currencyCode: deductible.currencyCode ? deductible.currencyCode : null
                        }
                    });
                }
            }

            // ===== PREMIUM LOGIC =====
            var premiumValue = null;
            var premiumCurrency = null;

            if (item.pricing && item.pricing.amounts && item.pricing.amounts.length > 0) {

                for (var k = 0; k < item.pricing.amounts.length; k++) {

                    var amt = item.pricing.amounts[k];

                    if (amt.amountTypeCode === "PREMIUM") {
                        premiumValue = amt.amountValue ? amt.amountValue : null;
                        premiumCurrency = amt.currencyCode ? amt.currencyCode : null;
                        break;
                    }
                }
            }


            var policyVersionObj = item.policyVersion ? item.policyVersion : {};

            // ===== Policy Event From First Record =====
            var policyEventObj = first.policyEvent ? first.policyEvent : {};

            return {

                endorsementId: item.endorsementId ? item.endorsementId : null,
                endorsementName: item.endorsementName ? item.endorsementName : null,
                endorsementCategory: item.endorsementCategory ? item.endorsementCategory : null,
                endorsementStatusCode: item.endorsementStatusCode ? item.endorsementStatusCode : null,
                endorsementEffectiveDate: item.endorsementEffectiveDate ? item.endorsementEffectiveDate : null,
                transactionDate: item.transactionDate ? item.transactionDate : null,

                policyVersion: {
                    policyVersionIdentifier: policyVersionObj.policyVersionIdentifier ? policyVersionObj.policyVersionIdentifier : null,
                    versionNumber: policyVersionObj.versionNumber ? policyVersionObj.versionNumber : null,
                    transactionTypeCode: policyVersionObj.transactionTypeCode ? policyVersionObj.transactionTypeCode : null,
                    versionEffectiveDate: policyVersionObj.versionEffectiveDate ? policyVersionObj.versionEffectiveDate : null
                },

                policyEvent: {
                    eventTypeCode: policyEventObj.eventTypeCode ? policyEventObj.eventTypeCode : null,
                    eventDate: policyEventObj.eventDate ? policyEventObj.eventDate : null
                },

                reprice: (typeof item.reprice !== "undefined") ? item.reprice : null,
                conflictHandling: item.conflictHandling ? item.conflictHandling : null,

                summary: {
                    driverChanges: {
                        addedCount: driverAdded.length,
                        updatedCount: driverUpdated.length,
                        removedCount: driverRemoved.length
                    },
                    vehicleChanges: {
                        addedCount: objAdded.length,
                        updatedCount: objUpdated.length,
                        removedCount: objRemoved.length
                    }
                },

                insurableObjects: insurableObjects,
                policyCoverages: policyCoverages,

                premium: {
                    amountValue: premiumValue,
                    currencyCode: premiumCurrency
                }
            };
        })
    };
}

mc.setPayloadJSON(result);
